# solution.py

class Plant:
    def __init__(self, name, growth_rate, water_requirement):
        self.name = name
        self.growth_rate = growth_rate
        self.water_requirement = water_requirement
        self.health = 100  # Health percentage

    def grow(self, water_available):
        if water_available >= self.water_requirement:
            self.health = min(100, self.health + self.growth_rate)
        else:
            self.health = max(0, self.health - self.growth_rate)

class Animal:
    def __init__(self, name, food_requirement, water_requirement):
        self.name = name
        self.food_requirement = food_requirement
        self.water_requirement = water_requirement
        self.health = 100  # Health percentage

    def eat(self, food_available):
        if food_available >= self.food_requirement:
            self.health = min(100, self.health + self.food_requirement)
        else:
            self.health = max(0, self.health - self.food_requirement)

    def drink(self, water_available):
        if water_available >= self.water_requirement:
            self.health = min(100, self.health + self.water_requirement)
        else:
            self.health = max(0, self.health - self.water_requirement)

class EcoSphere:
    def __init__(self):
        self.plants = []
        self.animals = []
        self.water = 1000  # Initial water resource
        self.food = 1000  # Initial food resource

    def add_plant(self, plant):
        self.plants.append(plant)

    def add_animal(self, animal):
        self.animals.append(animal)

    def simulate_day(self):
        for plant in self.plants:
            plant.grow(self.water)
            self.water -= plant.water_requirement

        for animal in self.animals:
            animal.eat(self.food)
            animal.drink(self.water)
            self.food -= animal.food_requirement
            self.water -= animal.water_requirement

    def display_status(self):
        print(f"Water: {self.water}, Food: {self.food}")
        for plant in self.plants:
            print(f"Plant: {plant.name}, Health: {plant.health}")
        for animal in self.animals:
            print(f"Animal: {animal.name}, Health: {animal.health}")

def main():
    eco_sphere = EcoSphere()
    eco_sphere.add_plant(Plant("Tree", 5, 10))
    eco_sphere.add_plant(Plant("Grass", 3, 5))
    eco_sphere.add_animal(Animal("Rabbit", 2, 3))
    eco_sphere.add_animal(Animal("Deer", 5, 7))

    for day in range(1, 31):
        print(f"Day {day}:")
        eco_sphere.simulate_day()
        eco_sphere.display_status()
        print()

if __name__ == "__main__":
    main()
```

